svg.script:
var lat  = 0;
var long = 0;


function locateMe() {
  if ( navigator.geolocation ) {
    navigator.geolocation.getCurrentPosition( handleLocation, handleError );
  } else {
    alert("¡Tu agente de usuario no soporta geolocalización!");
  }
}


function handleError( a ) {
  switch ( a.code ) {
    case 0: alert("Geolocation Error:\n\n error desconocido"); break;
    case 1: alert("Geolocation Error:\n\n La aplicación de origen no tiene permisos para usar la API de Geolocalización"); break;
    case 2: alert("Geolocation Error:\n\n La posición del dispositivo no pudo ser determinada"); break;
    case 3: alert("Geolocation Error:\n\n Se ha excedido el tiempo máximo antes de que se pudiera obtener la posición del dispositivo"); break;
  }
}


function handleLocation(loc) { 
  long = loc.coords.longitude;
  lat  = loc.coords.latitude;

  var url = "http://maps.google.com/maps?output=embed&z=16&ll=" + lat + "," + long + "&q=" + lat + "," + long + "+(You+are+here)";

  document.getElementById("long").textContent = long;
  document.getElementById("lat").textContent = lat;

  var map = document.getElementById("map");
  map.setAttribute("src", url);
  map.style.display = "inline";
}


function findThing(thing) {
  var url = "http://maps.google.com/maps?output=embed&amp;z=14&q=" + thing + "+loc:+" + lat + "," + long;
  document.getElementById("map").setAttribute("src", url);
}
